(function(){'use strict';document.documentElement.classList.add('js-enabled');document.addEventListener('DOMContentLoaded',function(){initNavbar();initScrollAnimations();initCounterAnimation();initSmoothScroll();initMobileMenu();initParallax();initTooltips();initFAQ();});function initNavbar(){const navbar=document.getElementById('navbar');let lastScroll=0;window.addEventListener('scroll',function(){const currentScroll=window.pageYOffset;if(currentScroll > 100){navbar.classList.add('scrolled');}else{navbar.classList.remove('scrolled');}lastScroll=currentScroll;});}function initScrollAnimations(){const observerOptions={threshold: 0.1,rootMargin: '0px 0px-50px 0px'};const observer=new IntersectionObserver(function(entries){entries.forEach(entry=>{if(entry.isIntersecting){const element=entry.target;const delay=element.getAttribute('data-delay')|| 0;setTimeout(()=>{element.classList.add('aos-animate');},delay);observer.unobserve(element);}});},observerOptions);document.querySelectorAll('[data-aos]').forEach(el=>{observer.observe(el);});}function initCounterAnimation(){const counters=document.querySelectorAll('.stat-number');const speed=50;const animateCounter=(counter)=>{const target=parseInt(counter.getAttribute('data-target'));const count=parseInt(counter.innerText);const increment=target/speed;const statItem=counter.closest('.stat-item');const statLabel=statItem ? statItem.querySelector('.stat-label'): null;const labelText=statLabel ? statLabel.textContent : '';let suffix='+';if(labelText.includes('%')){suffix='%';}else if(labelText.toLowerCase().includes('platform independent')){suffix='%';}else if(target===100){suffix='+';}if(count < target){counter.innerText=Math.ceil(count+increment);setTimeout(()=> animateCounter(counter),20);}else{counter.innerText=`${target}${suffix}`;}};const counterObserver=new IntersectionObserver(function(entries){entries.forEach(entry=>{if(entry.isIntersecting){const counter=entry.target;if(!counter.classList.contains('counted')){counter.classList.add('counted');animateCounter(counter);}counterObserver.unobserve(counter);}});},{threshold: 0.5});counters.forEach(counter=>{counter.innerText='0';counterObserver.observe(counter);});}function initSmoothScroll(){document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener('click',function(e){const href=this.getAttribute('href');if(href==='#')return;const target=document.querySelector(href);if(target){e.preventDefault();const offsetTop=target.offsetTop-80;window.scrollTo({top: offsetTop,behavior: 'smooth'});const mobileMenu=document.getElementById('mobileMenuToggle');if(mobileMenu){mobileMenu.classList.remove('active');document.querySelector('.nav-links')?.classList.remove('active');}}});});}function initMobileMenu(){const toggle=document.getElementById('mobileMenuToggle');const navLinks=document.querySelector('.nav-links');if(toggle && navLinks){toggle.addEventListener('click',function(){this.classList.toggle('active');navLinks.classList.toggle('active');});document.addEventListener('click',function(e){if(!toggle.contains(e.target)&& !navLinks.contains(e.target)){toggle.classList.remove('active');navLinks.classList.remove('active');}});}}function initParallax(){const hero=document.getElementById('hero');if(!hero)return;window.addEventListener('scroll',function(){const scrolled=window.pageYOffset;const rate=scrolled*0.5;if(scrolled < hero.offsetHeight){const orbs=hero.querySelectorAll('.gradient-orb');orbs.forEach((orb,index)=>{const speed=(index+1)*0.1;orb.style.transform=`translateY(${rate*speed}px)`;});}});}function initTooltips(){const tooltips=document.querySelectorAll('[data-tooltip]');tooltips.forEach(element=>{element.addEventListener('mouseenter',function(){const tooltip=document.createElement('div');tooltip.className='tooltip';tooltip.textContent=this.getAttribute('data-tooltip');document.body.appendChild(tooltip);const rect=this.getBoundingClientRect();tooltip.style.left=rect.left+(rect.width/2)-(tooltip.offsetWidth/2)+'px';tooltip.style.top=rect.top-tooltip.offsetHeight-10+'px';tooltip.classList.add('show');});element.addEventListener('mouseleave',function(){const tooltip=document.querySelector('.tooltip');if(tooltip){tooltip.remove();}});});}window.addEventListener('scroll',function(){const sections=document.querySelectorAll('section[id]');const navLinks=document.querySelectorAll('.nav-links a[href^="#"]');let current='';sections.forEach(section=>{const sectionTop=section.offsetTop;const sectionHeight=section.clientHeight;if(window.pageYOffset >=sectionTop-100){current=section.getAttribute('id');}});navLinks.forEach(link=>{link.classList.remove('active');if(link.getAttribute('href')===`#${current}`){link.classList.add('active');}});});document.querySelectorAll('.feature-card,.tool-category,.recognition-item').forEach(card=>{card.addEventListener('mouseenter',function(){this.style.transition='all 0.3s ease';});});document.querySelectorAll('.btn').forEach(button=>{button.addEventListener('click',function(e){const ripple=document.createElement('span');ripple.className='ripple';const rect=this.getBoundingClientRect();const size=Math.max(rect.width,rect.height);const x=e.clientX-rect.left-size/2;const y=e.clientY-rect.top-size/2;ripple.style.width=ripple.style.height=size+'px';ripple.style.left=x+'px';ripple.style.top=y+'px';this.appendChild(ripple);setTimeout(()=>{ripple.remove();},600);});});function throttle(func,wait){let timeout;return function executedFunction(...args){const later=()=>{clearTimeout(timeout);func(...args);};clearTimeout(timeout);timeout=setTimeout(later,wait);};}window.addEventListener('scroll',throttle(function(){},16));function copyToClipboard(text){navigator.clipboard.writeText(text).then(function(){const notification=document.createElement('div');notification.className='copy-notification';notification.textContent='Copied to clipboard!';document.body.appendChild(notification);setTimeout(()=>{notification.remove();},2000);}).catch(function(err){console.error('Failed to copy: ',err);});}window.copyToClipboard=copyToClipboard;window.addEventListener('load',function(){document.body.classList.add('loaded');});function initFAQ(){const faqItems=document.querySelectorAll('.faq-item');faqItems.forEach(item=>{const question=item.querySelector('.faq-question');const answer=item.querySelector('.faq-answer');question.addEventListener('click',function(){faqItems.forEach(otherItem=>{if(otherItem !==item){otherItem.classList.remove('active');otherItem.querySelector('.faq-answer').classList.remove('show');}});item.classList.toggle('active');answer.classList.toggle('show');});});}console.log('%c🦅 Nightingale v2.0','color: #7395AE;font-size: 20px;font-weight: bold;');console.log('%cDocker for Pentesters-Landing Page','color: #A1D6E2;font-size: 14px;');console.log('%cBuilt with ❤️ for the security community','color: #7A8A9A;font-size: 12px;');})();